                const std::string localPtr = "%" + localName + ".addr";
                body += "  " + localPtr + " = alloca " + nativeScalarLlvmType(lowered.typeName) + "\n";
                body += "  store " + nativeScalarLlvmType(lowered.typeName) + " " + lowered.value + ", ptr " + localPtr + "\n";
