                    body += "  " + tagTemp + " = extractvalue " + nativeLlvmTypeRef(aggregate.typeName) + " " + aggregate.value + ", 0\n";
                    body += "  " + conditionTemp + " = icmp eq i32 " + tagTemp + ", " + std::to_string(discriminant->second) + "\n";
